// Cloudflare Worker with SendGrid and Stripe Integration

const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
const STRIPE_SECRET_KEY = 'YOUR_STRIPE_SECRET_KEY';
const ALLOWED_ORIGINS = ['https://yourdomain.com'];

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Content-Type': 'application/json'
};

async function handleRequest(request) {
  if (request.method === 'OPTIONS') {
    return new Response(null, {
      headers: corsHeaders
    });
  }

  const url = new URL(request.url);
  const path = url.pathname;

  try {
    if (!authenticateRequest(request)) {
      return errorResponse('Unauthorized', 401);
    }

    if (path === '/send-email' && request.method === 'POST') {
      return await handleSendEmail(request);
    }

    if (path === '/create-payment-intent' && request.method === 'POST') {
      return await handleCreatePaymentIntent(request);
    }

    if (path === '/create-customer' && request.method === 'POST') {
      return await handleCreateCustomer(request);
    }

    if (path === '/webhook/stripe' && request.method === 'POST') {
      return await handleStripeWebhook(request);
    }

    if (path === '/charge' && request.method === 'POST') {
      return await handleCharge(request);
    }

    if (path === '/send-template-email' && request.method === 'POST') {
      return await handleSendTemplateEmail(request);
    }

    return errorResponse('Not Found', 404);
  } catch (error) {
    console.error('Error:', error);
    return errorResponse(error.message || 'Internal Server Error', 500);
  }
}

function authenticateRequest(request) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return false;
  }

  const token = authHeader.substring(7);
  return token === 'YOUR_API_SECRET_TOKEN';
}

async function handleSendEmail(request) {
  try {
    const body = await request.json();
    const { to, from, subject, text, html } = body;

    if (!to || !from || !subject || (!text && !html)) {
      return errorResponse('Missing required fields: to, from, subject, and text or html', 400);
    }

    const emailData = {
      personalizations: [
        {
          to: [{ email: to }]
        }
      ],
      from: { email: from },
      subject: subject,
      content: []
    };

    if (text) {
      emailData.content.push({
        type: 'text/plain',
        value: text
      });
    }

    if (html) {
      emailData.content.push({
        type: 'text/html',
        value: html
      });
    }

    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SENDGRID_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(emailData)
    });

    if (!response.ok) {
      const errorData = await response.text();
      throw new Error(`SendGrid API error: ${response.status} - ${errorData}`);
    }

    return successResponse({
      message: 'Email sent successfully',
      status: 'success'
    });
  } catch (error) {
    return errorResponse(`Email sending failed: ${error.message}`, 500);
  }
}

async function handleSendTemplateEmail(request) {
  try {
    const body = await request.json();
    const { to, from, templateId, dynamicTemplateData } = body;

    if (!to || !from || !templateId) {
      return errorResponse('Missing required fields: to, from, templateId', 400);
    }

    const emailData = {
      personalizations: [
        {
          to: [{ email: to }],
          dynamic_template_data: dynamicTemplateData || {}
        }
      ],
      from: { email: from },
      template_id: templateId
    };

    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SENDGRID_API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(emailData)
    });

    if (!response.ok) {
      const errorData = await response.text();
      throw new Error(`SendGrid API error: ${response.status} - ${errorData}`);
    }

    return successResponse({
      message: 'Template email sent successfully',
      status: 'success'
    });
  } catch (error) {
    return errorResponse(`Template email sending failed: ${error.message}`, 500);
  }
}

async function handleCreatePaymentIntent(request) {
  try {
    const body = await request.json();
    const { amount, currency, metadata } = body;

    if (!amount || !currency) {
      return errorResponse('Missing required fields: amount, currency', 400);
    }

    if (amount < 50) {
      return errorResponse('Amount must be at least 50 cents', 400);
    }

    const paymentIntentData = new URLSearchParams({
      amount: amount.toString(),
      currency: currency.toLowerCase()
    });

    if (metadata) {
      for (const [key, value] of Object.entries(metadata)) {
        paymentIntentData.append(`metadata[${key}]`, value);
      }
    }

    const response = await fetch('https://api.stripe.com/v1/payment_intents', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: paymentIntentData.toString()
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.error?.message || 'Stripe API error');
    }

    return successResponse({
      clientSecret: data.client_secret,
      paymentIntentId: data.id,
      status: data.status
    });
  } catch (error) {
    return errorResponse(`Payment intent creation failed: ${error.message}`, 500);
  }
}

async function handleCreateCustomer(request) {
  try {
    const body = await request.json();
    const { email, name, metadata } = body;

    if (!email) {
      return errorResponse('Missing required field: email', 400);
    }

    const customerData = new URLSearchParams({
      email: email
    });

    if (name) {
      customerData.append('name', name);
    }

    if (metadata) {
      for (const [key, value] of Object.entries(metadata)) {
        customerData.append(`metadata[${key}]`, value);
      }
    }

    const response = await fetch('https://api.stripe.com/v1/customers', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: customerData.toString()
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.error?.message || 'Stripe API error');
    }

    return successResponse({
      customerId: data.id,
      email: data.email,
      created: data.created
    });
  } catch (error) {
    return errorResponse(`Customer creation failed: ${error.message}`, 500);
  }
}

async function handleCharge(request) {
  try {
    const body = await request.json();
    const { amount, currency, source, description } = body;

    if (!amount || !currency || !source) {
      return errorResponse('Missing required fields: amount, currency, source', 400);
    }

    const chargeData = new URLSearchParams({
      amount: amount.toString(),
      currency: currency.toLowerCase(),
      source: source
    });

    if (description) {
      chargeData.append('description', description);
    }

    const response = await fetch('https://api.stripe.com/v1/charges', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: chargeData.toString()
    });

    const data = await response.json();

    if (!response.ok) {
      throw new Error(data.error?.message || 'Stripe API error');
    }

    return successResponse({
      chargeId: data.id,
      amount: data.amount,
      status: data.status,
      paid: data.paid
    });
  } catch (error) {
    return errorResponse(`Charge failed: ${error.message}`, 500);
  }
}

async function handleStripeWebhook(request) {
  try {
    const body = await request.text();
    const signature = request.headers.get('stripe-signature');

    if (!signature) {
      return errorResponse('Missing stripe-signature header', 400);
    }

    const event = JSON.parse(body);

    switch (event.type) {
      case 'payment_intent.succeeded':
        console.log('PaymentIntent succeeded:', event.data.object.id);
        break;
      case 'payment_intent.payment_failed':
        console.log('PaymentIntent failed:', event.data.object.id);
        break;
      case 'customer.created':
        console.log('Customer created:', event.data.object.id);
        break;
      case 'charge.succeeded':
        console.log('Charge succeeded:', event.data.object.id);
        break;
      default:
        console.log('Unhandled event type:', event.type);
    }

    return successResponse({
      received: true,
      eventType: event.type
    });
  } catch (error) {
    return errorResponse(`Webhook processing failed: ${error.message}`, 400);
  }
}

function successResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: corsHeaders
  });
}

function errorResponse(message, status = 400) {
  return new Response(JSON.stringify({
    error: message,
    status: 'error'
  }), {
    status,
    headers: corsHeaders
  });
}

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});